package com.museumheist.game;import com.museumheist.game.entity.PowerUp;import org.junit.Test;import static org.junit.Assert.*;public class GameStateTest{@Test public void reset(){GameState s=new GameState();s.reset(3);assertTrue(s.isPlaying());assertEquals(3,s.getTreasureCount());}@Test public void collectOnce(){GameState s=new GameState();s.reset(2);assertTrue(s.collectTreasure(1));assertFalse(s.collectTreasure(1));assertEquals(1,s.getCollectedTreasureCount());}@Test public void all(){GameState s=new GameState();s.reset(2);s.collectTreasure(0);assertFalse(s.hasAllTreasures());s.collectTreasure(1);assertTrue(s.hasAllTreasures());}@Test public void pause(){GameState s=new GameState();s.reset();s.pause();assertTrue(s.isPaused());s.resumePlaying();assertTrue(s.isPlaying());}@Test public void fail(){GameState s=new GameState();s.reset();s.fail("caught");assertTrue(s.isFailed());assertEquals("caught",s.getFailureReason());}@Test public void slots(){GameState s=new GameState();s.reset();s.storePowerUp(PowerUp.Type.CLOAK);s.storePowerUp(PowerUp.Type.SPEED);s.storePowerUp(PowerUp.Type.JAMMER);assertEquals(2,s.getStoredPowerUpCount());assertFalse(s.canStorePowerUp());}@Test public void cloak(){GameState s=new GameState();s.reset();s.storePowerUp(PowerUp.Type.CLOAK);assertTrue(s.useStoredPowerUp(0));assertTrue(s.isInvisible());s.update(GameConfig.POWER_UP_EFFECT_SECONDS+.1f,false);assertFalse(s.isInvisible());}@Test public void speed(){GameState s=new GameState();s.reset();s.storePowerUp(PowerUp.Type.SPEED);s.useStoredPowerUp(0);assertTrue(s.isSpeedPotionActive());assertNull(s.getActivePowerUp());}@Test public void boost(){GameState s=new GameState();s.reset();s.addBoostEnergy(5);assertEquals(1,s.getBoostEnergy(),.001f);s.update(GameConfig.BOOST_FULL_USE_SECONDS,true);assertEquals(0,s.getBoostEnergy(),.001f);}}